previewCss:
.darma-loader-darma-custom-606 {color: var(--loader-color, #0891b2);
   width: 96px;
   height: 60px;
   padding: 10px;
   box-sizing: border-box;
   display: flex;
   justify-content: space-between;
   background: currentColor;
   filter: blur(5px) contrast(10) hue-rotate(60deg);
   mix-blend-mode: darken;
}
.darma-loader-darma-custom-606:before, .darma-loader-darma-custom-606:after  {
  content: "";
   width: 40px;
   border-radius: 50%;
   background: #ff00ff;
   animation: darma-loader-darma-custom-606-l3 1s infinite alternate;
}
.darma-loader-darma-custom-606:after  {
  --s:-1;
}
@keyframes darma-loader-darma-custom-606-l3 {
  90%,100% {transform: translate(calc(var(--s,1)*30px))}
}

